import React, { useState, useEffect } from 'react';
import { 
  Box, 
  Typography, 
  InputBase, 
  IconButton, 
  Chip, 
  Grid, 
  Button, 
  Stack, 
  Select, 
  MenuItem, 
  FormControl, 
  Divider, 
  useMediaQuery,
  SwipeableDrawer,
  Container,
  Paper,
  CircularProgress,
  Badge,
  Avatar,
  Fade,
  Backdrop
} from '@mui/material';
import { 
  Search, 
  FilterList, 
  DirectionsCar, 
  LocalOffer, 
  Close, 
  Tune,
  TrendingUp,
  AccessTime,
  NewReleases,
  Smartphone,
  SportsEsports,
  CardGiftcard,
  Favorite,
  AccountBalanceWallet,
  AddCircleOutline,
  Payment,
  ChevronRight,
  CarRental,
  ArrowForward,
  ArrowDownward,
  CheckCircle,
  Star,
  LocalAtm
} from '@mui/icons-material';
import { styled, alpha, useTheme } from '@mui/material/styles';
import { motion, AnimatePresence } from 'framer-motion';
import { Link, useNavigate } from 'react-router-dom';
import CarCard from '../components/cards/CarCard';
import CompanySelector from '../components/company/CompanySelector';
import { useFirebase } from '../context/FirebaseContext';
import WalletWidget from '../components/wallet/WalletWidget';
import { getUserFavorites, toggleFavoriteRaffle } from '../firebase/services';

// Стилизованные компоненты
const SearchContainer = styled(Box)(({ theme }) => ({
  position: 'relative',
  borderRadius: 20,
  backgroundColor: alpha(theme.palette.background.paper, 1),
  boxShadow: theme.palette.mode === 'light' 
    ? '0 8px 32px rgba(0,0,0,0.06)' 
    : '0 8px 32px rgba(0,0,0,0.2)',
  width: '100%',
  marginBottom: theme.spacing(3),
  transition: 'all 0.3s ease',
  overflow: 'hidden',
  '&:hover': {
    boxShadow: theme.palette.mode === 'light' 
      ? '0 12px 36px rgba(0,0,0,0.1)' 
      : '0 12px 36px rgba(0,0,0,0.3)',
    transform: 'translateY(-2px)',
  },
}));

const SearchIconWrapper = styled('div')(({ theme }) => ({
  padding: theme.spacing(0, 2),
  height: '100%',
  position: 'absolute',
  pointerEvents: 'none',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  color: alpha(theme.palette.text.secondary, 0.7),
}));

const StyledInputBase = styled(InputBase)(({ theme }) => ({
  width: '100%',
  '& .MuiInputBase-input': {
    padding: theme.spacing(2, 1.5, 2, 0),
    paddingLeft: `calc(1em + ${theme.spacing(4)})`,
    transition: theme.transitions.create('width'),
    width: '100%',
    fontSize: '1rem',
  },
}));

const FilterChip = styled(Chip)(({ theme }) => ({
  margin: theme.spacing(0, 0.5, 1, 0),
  backgroundColor: alpha(theme.palette.primary.main, 0.08),
  color: theme.palette.primary.main,
  fontWeight: 600,
  borderRadius: 16,
  padding: theme.spacing(0.5, 0.5),
  height: 34,
  '&.MuiChip-clickable:hover': {
    backgroundColor: alpha(theme.palette.primary.main, 0.15),
    transform: 'translateY(-1px)',
  },
  '&.Mui-selected': {
    backgroundColor: alpha(theme.palette.primary.main, 0.8),
    color: theme.palette.common.white,
    '&:hover': {
      backgroundColor: theme.palette.primary.main,
    }
  }
}));

const CategoryChip = styled(Chip)(({ theme }) => ({
  margin: theme.spacing(0, 0.8, 1, 0),
  fontWeight: 600,
  borderRadius: 16,
  boxShadow: '0 4px 16px rgba(0,0,0,0.08)',
  padding: theme.spacing(0.5, 0.5),
  height: 42,
  transition: 'all 0.2s ease',
  '&.MuiChip-clickable:hover': {
    boxShadow: '0 8px 20px rgba(0,0,0,0.15)',
    transform: 'translateY(-2px)',
  }
}));

const ModernHeroSection = styled(Box)(({ theme }) => ({
  position: 'relative',
  overflow: 'hidden',
  borderRadius: 32,
  paddingTop: theme.spacing(8),
  paddingBottom: theme.spacing(12),
  marginBottom: theme.spacing(6),
  background: `linear-gradient(135deg, ${theme.palette.primary.dark} 0%, ${theme.palette.primary.main} 100%)`,
  [theme.breakpoints.down('md')]: {
    paddingTop: theme.spacing(6),
    paddingBottom: theme.spacing(10),
  },
}));

const HeroContent = styled(Box)(({ theme }) => ({
  position: 'relative',
  zIndex: 2,
  padding: theme.spacing(0, 4),
  maxWidth: '1200px',
  margin: '0 auto',
  [theme.breakpoints.down('sm')]: {
    padding: theme.spacing(0, 2),
  },
}));

const HeroBadge = styled(Box)(({ theme }) => ({
  display: 'inline-flex',
  alignItems: 'center',
  borderRadius: 50,
  padding: theme.spacing(0.6, 2),
  backgroundColor: alpha(theme.palette.common.white, 0.15),
  backdropFilter: 'blur(10px)',
  color: theme.palette.common.white,
  marginBottom: theme.spacing(2),
  fontWeight: 600,
  fontSize: '0.85rem',
  boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
  '& svg': {
    marginRight: theme.spacing(0.8),
    fontSize: '1rem',
  },
}));

const HeroTitle = styled(Typography)(({ theme }) => ({
  color: theme.palette.common.white,
  fontWeight: 800,
  marginBottom: theme.spacing(2),
  textShadow: '0 2px 6px rgba(0,0,0,0.2)',
  fontSize: '3.5rem',
  lineHeight: 1.2,
  [theme.breakpoints.down('md')]: {
    fontSize: '2.5rem',
  },
  [theme.breakpoints.down('sm')]: {
    fontSize: '2rem',
  },
}));

const HeroDescription = styled(Typography)(({ theme }) => ({
  color: alpha(theme.palette.common.white, 0.9),
  fontSize: '1.2rem',
  marginBottom: theme.spacing(4),
  maxWidth: '600px',
  lineHeight: 1.6,
  textShadow: '0 1px 4px rgba(0,0,0,0.1)',
  [theme.breakpoints.down('sm')]: {
    fontSize: '1rem',
  },
}));

const HeroButton = styled(Button)(({ theme }) => ({
  borderRadius: 50,
  padding: theme.spacing(1.5, 4),
  fontWeight: 700,
  textTransform: 'none',
  fontSize: '1rem',
  boxShadow: '0 8px 20px rgba(0,0,0,0.2)',
  transition: 'all 0.3s ease',
  '&:hover': {
    boxShadow: '0 12px 24px rgba(0,0,0,0.25)',
    transform: 'translateY(-4px)',
  },
}));

const HeroImageContainer = styled(Box)(({ theme }) => ({
  position: 'absolute',
  right: 0,
  bottom: -80,
  width: '50%',
  height: '130%',
  zIndex: 1,
  [theme.breakpoints.down('md')]: {
    width: '70%',
    opacity: 0.6,
  },
  [theme.breakpoints.down('sm')]: {
    opacity: 0.3,
  },
}));

const HeroImage = styled('img')(({ theme }) => ({
  width: '100%',
  height: '100%',
  objectFit: 'contain',
  filter: 'drop-shadow(0 20px 40px rgba(0,0,0,0.3))',
  transform: 'scale(1.1)',
}));

const HeroGlow = styled(Box)(({ theme }) => ({
  position: 'absolute',
  width: '50%',
  height: '50%',
  borderRadius: '50%',
  background: `radial-gradient(ellipse at center, ${alpha(theme.palette.primary.light, 0.3)} 0%, ${alpha(theme.palette.primary.light, 0)} 70%)`,
  filter: 'blur(50px)',
  zIndex: 0,
}));

const HeroStats = styled(Box)(({ theme }) => ({
  display: 'flex',
  gap: theme.spacing(4),
  marginBottom: theme.spacing(4),
  [theme.breakpoints.down('sm')]: {
    flexDirection: 'column',
    gap: theme.spacing(2),
  },
}));

const HeroStat = styled(Box)(({ theme }) => ({
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'flex-start',
}));

const HeroStatValue = styled(Typography)(({ theme }) => ({
  color: theme.palette.common.white,
  fontWeight: 800,
  fontSize: '2rem',
  lineHeight: 1,
  marginBottom: theme.spacing(0.5),
}));

const HeroStatLabel = styled(Typography)(({ theme }) => ({
  color: alpha(theme.palette.common.white, 0.7),
  fontSize: '0.9rem',
}));

const SectionHeader = styled(Box)(({ theme }) => ({
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: theme.spacing(3),
}));

const SectionTitle = styled(Typography)(({ theme }) => ({
  fontWeight: 700,
  fontSize: '1.5rem',
  display: 'flex',
  alignItems: 'center',
  '& .MuiSvgIcon-root': {
    marginRight: theme.spacing(1),
    color: theme.palette.primary.main
  }
}));

const ViewAllButton = styled(Button)(({ theme }) => ({
  textTransform: 'none',
  fontWeight: 600,
  borderRadius: 20,
  '&:hover': {
    backgroundColor: alpha(theme.palette.primary.main, 0.05),
  },
}));

const FilterDrawerContent = styled(Box)(({ theme }) => ({
  width: 320,
  padding: theme.spacing(3),
  [theme.breakpoints.down('sm')]: {
    width: '100vw',
  },
}));

const BalanceCard = styled(Paper)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(2.5),
  boxShadow: '0 8px 24px rgba(0,0,0,0.1)',
  marginBottom: theme.spacing(4),
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  background: `linear-gradient(135deg, ${alpha(theme.palette.primary.main, 0.08)} 0%, ${alpha(theme.palette.primary.dark, 0.05)} 100%)`,
