                  <Star fontSize="small" />
                  Уже более 250 счастливых победителей
                </HeroBadge>
              </motion.div>
              
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.2, duration: 0.6 }}
              >
