                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.3, duration: 0.6 }}
              >
                <HeroDescription>
                  Участвуй в розыгрышах роскошных автомобилей всего от 500 ₽.
                  Прозрачная система, честные победители, быстрые выплаты.
                </HeroDescription>
              </motion.div>
              
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.4, duration: 0.6 }}
              >
                <HeroStats>
                  <HeroStat>
                    <HeroStatValue>250+</HeroStatValue>
                    <HeroStatLabel>Победителей</HeroStatLabel>
                  </HeroStat>
                  <HeroStat>
                    <HeroStatValue>50+</HeroStatValue>
                    <HeroStatLabel>Розыгрышей</HeroStatLabel>
                  </HeroStat>
                  <HeroStat>
                    <HeroStatValue>от 500 ₽</HeroStatValue>
                    <HeroStatLabel>Стоимость билета</HeroStatLabel>
                  </HeroStat>
                </HeroStats>
              </motion.div>
              
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.5, duration: 0.6 }}
              >
                <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap' }}>
                  <HeroButton
                    variant="contained"
                    size="large"
                    startIcon={<CarRental />}
                    color="primary"
                  >
                    Участвовать сейчас
                  </HeroButton>
                  
                  <HeroButton
                    variant="outlined"
                    size="large"
                    endIcon={<ArrowForward />}
                    sx={{ 
                      backgroundColor: 'rgba(255,255,255,0.1)', 
                      borderColor: 'rgba(255,255,255,0.3)',
                      color: 'white',
                      '&:hover': {
                        backgroundColor: 'rgba(255,255,255,0.2)',
                        borderColor: 'rgba(255,255,255,0.5)',
                      }
                    }}
                  >
                    Как это работает
                  </HeroButton>
                </Box>
              </motion.div>
            </HeroContent>
            
            <HeroImageContainer>
              <HeroImage src="https://i.postimg.cc/28QPpVX4/1.png" alt="Автомобиль мечты" />
            </HeroImageContainer>
          </ModernHeroSection>
          
          {/* Блок с балансом */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2, duration: 0.6 }}
          >
            <BalanceCard>
