                    label={filter.label} 
                    clickable 
                    onClick={() => setSelectedPrice(filter.id)}
                    className={selectedPrice === filter.id ? 'Mui-selected' : ''}
                  />
                ))}
              </Stack>
              
              <Typography variant="subtitle2" sx={{ mb: 2, fontWeight: 600, color: theme.palette.text.secondary }}>
                Марка автомобиля
              </Typography>
              <Stack direction="row" spacing={1} sx={{ mb: 4, flexWrap: 'wrap' }}>
                {brandFilters.map(filter => (
                  <FilterChip 
                    key={filter.id}
                    label={filter.label} 
                    clickable 
                    onClick={() => setSelectedBrand(filter.id)}
                    className={selectedBrand === filter.id ? 'Mui-selected' : ''}
                  />
                ))}
              </Stack>
              
              <Divider sx={{ my: 3 }} />
              
              <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 4 }}>
                <Button 
                  variant="text" 
                  onClick={resetFilters}
                  sx={{ 
                    color: theme.palette.text.secondary,
                    fontWeight: 600,
                    '&:hover': {
                      backgroundColor: alpha(theme.palette.primary.main, 0.05),
                    }
                  }}
                >
                  Сбросить все
                </Button>
                <Button 
                  variant="contained" 
                  onClick={applyFilters}
                  sx={{ 
                    boxShadow: '0 4px 16px rgba(0,0,0,0.15)',
                    borderRadius: 20,
                    px: 4,
                    fontWeight: 600,
                    textTransform: 'none'
                  }}
                >
                  Применить
                </Button>
              </Box>
            </FilterDrawerContent>
          </SwipeableDrawer>
        </motion.div>
      </AnimatePresence>
    </Container>
  );
};

export default HomePage;
